export enum Status {
  Active = 'Active',
  Pending = 'Pending',
  Closed = 'Closed',
  Critical = 'Critical',
  Warning = 'Warning',
  Good = 'Good',
  OnTrack = 'On Track',
  AtRisk = 'At Risk',
  Overdue = 'Overdue',
  Planning = 'Planning',
  UnderReview = 'Under Review',
  Approved = 'Approved',
  Rejected = 'Rejected',
}

export interface Notification {
  id: string;
  message: string;
  type: 'alert' | 'info' | 'task';
  timestamp: string;
  isRead: boolean;
  link?: string;
}

export interface Document {
  id: string;
  name: string;
  type: 'PDF' | 'CAD' | 'Lease Agreement' | 'Invoice' | 'Permit' | 'Contract' | 'Blueprint' | 'Insurance Policy' | 'Compliance Report' | 'Purchase Order' | 'Change Order' | 'Appraisal Report' | 'Conveyance' | 'NEPA Study' | 'Disposal Authorization' | 'Determination of Excess' | 'Relocation Notice' | 'Benefit Claim' | 'Remediation Plan' | 'Solicitation Package' | 'Bid Response' | 'Legal Correspondence' | 'Evidence' | 'Cost Share Agreement' | 'Inspection Report' | 'Regulatory Permit' | 'Deed' | 'Easement Agreement';
  url: string;
  uploadedDate: string;
  size: string;
  relatedTo: string; // e.g., 'Property P001', 'Project CP-02'
}

export interface Property {
  id: string;
  name: string;
  address: string;
  type: 'Office' | 'Industrial' | 'Retail' | 'Lab';
  sizeSqFt: number;
  occupancyRate: number;
  status: Status;
  marketValue: number;
  imageUrl: string;
  documents?: Document[];
  noi: number; // Net Operating Income
  fci: number; // Facility Condition Index (0-100)
}

export interface Lease {
  id:string;
  propertyId: string;
  tenantName: string;
  startDate: string;
  endDate: string;
  monthlyRent: number;
  status: 'Active' | 'Expiring Soon' | 'Expired';
  criticalDates: { name: string; date: string }[];
  camCharge: number;
  clauses?: LeaseClause[];
}

export interface LeaseClause {
  id: string;
  leaseId: string;
  name: 'Renewal Option' | 'Termination Option' | 'Rent Escalation' | 'CAM Cap';
  details: string;
  criticalDate?: string;
}

export interface Contract {
  id: string;
  name: string;
  vendorId: string;
  type: 'Service' | 'Lease' | 'Construction';
  startDate: string;
  endDate: string;
  value: number;
  status: 'Draft' | 'Active' | 'Expired' | 'Terminated';
  renewalDate: string;
  documentId: string;
}

export interface Transaction {
  id: string;
  propertyId: string;
  type: 'Acquisition' | 'Disposition';
  stage: 'Prospecting' | 'Due Diligence' | 'Negotiation' | 'Closing';
  dealValue: number;
  closeDate: string;
  broker: string;
}

export interface MoveRequest {
  id: string;
  employeeName: string;
  fromLocation: string;
  toLocation: string;
  moveDate: string;
  status: 'Requested' | 'Approved' | 'Scheduled' | 'Completed';
}

export interface Workflow {
  id: string;
  name: string;
  trigger: string;
  actions: string[];
  enabled: boolean;
}

export interface Vendor {
  id: string;
  name: string;
  trade: 'HVAC' | 'Plumbing' | 'Electrical' | 'General Contractor' | 'Janitorial';
  rating: number; // 1-5
  onTimeCompletionRate: number; // 0-100
  avgInvoiceCost: number;
}

export interface CostCenter {
  id: string;
  name: string;
  owner: string; // employeeId
  budget: number;
  spent: number;
}

export interface WorkOrder {
  id: string;
  title: string;
  propertyId: string;
  priority: 'Low' | 'Medium' | 'High' | 'Emergency';
  status: 'Open' | 'In Progress' | 'Completed' | 'On Hold';
  category: 'HVAC' | 'Plumbing' | 'Electrical' | 'General' | 'Corrective' | 'Preventive';
  assignedTo: string; // employeeId or vendorId
  dueDate: string;
  cost: number;
  costCenterId: string;
  assetId?: string; // Integration Point
  relatedIncidentId?: string; // Integration Point
}

export interface InventoryItem {
  id: string;
  name: string;
  sku: string;
  stock: number;
  reorderLevel: number;
  location: string;
  costPerUnit: number;
}

export interface SafetyIncident {
  id: string;
  propertyId: string;
  type: 'Injury' | 'Property Damage' | 'Near Miss' | 'Environmental';
  date: string;
  severity: 'Low' | 'Medium' | 'High' | 'Critical';
  status: 'Open' | 'Under Investigation' | 'Closed' | 'Corrective Action Pending';
  description: string;
}

export interface Asset {
  id: string;
  name: string;
  serialNumber: string;
  purchaseDate: string;
  warrantyEnd: string;
  condition: number; // 0-100
  location: string;
  propertyId: string;
  maintenanceCostYTD?: number;
  downtimeHours?: number;
}

export interface PreventiveMaintenanceSchedule {
  id: string;
  assetId: string;
  task: string;
  frequency: 'Weekly' | 'Monthly' | 'Quarterly' | 'Annually';
  nextDueDate: string;
  lastCompletedDate?: string;
  status: 'Scheduled' | 'Overdue' | 'Completed';
}

export interface SpaceMetric {
  floor: string;
  utilization: number; // 0-100
  department: string;
  seatsTotal: number;
  seatsAvailable: number;
}

export interface Employee {
  id: string;
  name: string;
  title: string;
  department: string;
  email: string;
  location: string; // Assigned desk/office
  phone: string;
  imageUrl: string;
}

export interface ServiceRequest {
  id: string;
  submittedBy: string; // employeeId
  type: 'Temperature' | 'Maintenance' | 'Janitorial' | 'IT';
  location: string;
  status: 'New' | 'In Progress' | 'Resolved';
  createdDate: string;
  details: string;
}

export interface SustainabilityMetric {
  month: string;
  energyKWh: number;
  waterGal: number;
  carbonTons: number;
  wasteKg: number;
  recyclingKg: number;
}

export interface SustainabilityInitiative {
  id: string;
  name: string;
  type: 'Energy' | 'Water' | 'Waste';
  status: 'Planning' | 'In Progress' | 'Completed';
  projectedSavings: string;
  completionDate: string;
}

export interface BudgetLineItem {
  id: string;
  category: 'Labor' | 'Materials' | 'Contingency' | 'Permits' | 'Vendor' | 'Design';
  budgeted: number;
  actual: number;
  variance: number;
}

export interface ProjectRisk {
  id: string;
  description: string;
  impact: 'Low' | 'Medium' | 'High';
  probability: 'Low' | 'Medium' | 'High';
  mitigation: string;
}

export interface CapitalProject {
  id: string;
  name: string;
  propertyId: string;
  type: 'Renovation' | 'New Construction' | 'Major Repair';
  status: Status;
  startDate: string;
  endDate: string;
  totalBudget: number;
  spent: number;
  manager: string; // employeeId
  budgetItems?: BudgetLineItem[];
  risks?: ProjectRisk[];
  documents?: Document[];
  milestones?: ProjectMilestone[];
  changeOrders?: ChangeOrder[];
}

export interface ProjectMilestone {
  id: string;
  name: string;
  dueDate: string;
  status: 'Not Started' | 'In Progress' | 'Completed';
}

export interface ChangeOrder {
  id: string;
  projectId: string;
  title: string;
  reason: 'Client Request' | 'Unforeseen Condition' | 'Design Change';
  costImpact: number;
  scheduleImpactDays: number;
  status: 'Pending' | 'Approved' | 'Rejected';
  date: string;
}

export interface AuditLog {
  id: string;
  user: string; // employee name
  action: string;
  entity: string; // e.g. "Lease L-102"
  timestamp: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: 'Admin' | 'Facility Manager' | 'Technician' | 'Read Only' | 'Financial Analyst' | 'Project Manager' | 'Disposal Officer' | 'Relocation Specialist' | 'Environmental Specialist' | 'Contracting Officer' | 'Legal Officer' | 'Mobilization Planner' | 'Cost-Share Manager' | 'Out-Grant Admin' | 'Regulatory Specialist' | 'Real Property Accountable Officer';
  lastLogin: string;
}

// NEW INTERFACES FOR EXPANDED FEATURES

export interface Reservation {
  id: string;
  spaceId: string; // e.g. 'HQ-Conf-A', 'HQ-Flex-05'
  spaceName: string;
  reservedBy: string; // employeeId
  date: string;
  startTime: string;
  endTime: string;
  status: 'Confirmed' | 'Cancelled';
}

export interface Visitor {
  id: string;
  name: string;
  company: string;
  host: string; // employeeId
  arrival: string; // ISO datetime
  departure?: string; // ISO datetime
  status: 'Expected' | 'Checked In' | 'Checked Out';
}

export interface ComplianceTask {
  id: string;
  name: string;
  type: 'Permit Renewal' | 'Inspection' | 'Audit';
  propertyId: string;
  dueDate: string;
  status: 'Pending' | 'In Progress' | 'Completed' | 'Overdue';
  assignedTo: string; // employeeId
}

export interface InsurancePolicy {
  id: string;
  propertyId: string;
  provider: string;
  policyNumber: string;
  type: 'Property' | 'Liability' | 'Workers Comp';
  coverageAmount: number;
  premium: number;
  expiryDate: string;
}

export interface UtilityBill {
  id: string;
  propertyId: string;
  utility: 'Electric' | 'Gas' | 'Water' | 'Waste';
  serviceDate: string; // e.g. '2023-10'
  cost: number;
  consumption: number;
  unit: 'kWh' | 'therms' | 'gallons' | 'kg';
  documentId: string;
}

export interface ParkingPermit {
  id: string;
  permitNumber: string;
  assignedTo: string; // employeeId
  lot: string;
  spot?: string;
  vehicle: string; // Make, model, plate
  expiryDate: string;
}

export interface KeyRecord {
  id: string;
  keyNumber: string;
  type: 'Physical Key' | 'Access Card' | 'Fob';
  assignedTo: string; // employeeId
  accesses: string; // e.g. 'HQ Main Entrance, Server Room'
  issueDate: string;
  returnDate?: string;
}

export interface ConditionAssessment {
  id: string;
  assetId: string;
  assessmentDate: string;
  assessedBy: string; // employeeId
  conditionScore: number; // 0-100
  notes: string;
  recommendedAction: string;
}

// --- NEW FINANCIALS & PPBE INTERFACES ---

export interface PpbeFund {
  id: string;
  name: string;
  appropriationType: 'O&M' | 'MILCON' | 'RDT&E' | 'Procurement';
  fiscalYear: number;
  programElement: string;
  totalAmount: number;
  committed: number;
  obligated: number;
  expended: number;
}

export interface FundTransaction {
  id: string;
  fundId: string;
  projectId?: string;
  workOrderId?: string;
  relocationCaseId?: string;
  environmentalSiteId?: string; 
  legalClaimId?: string;
  type: 'Commitment' | 'Obligation' | 'Expenditure';
  amount: number;
  date: string;
  description: string;
}

export interface UnfundedRequirement {
  id: string;
  title: string;
  propertyId: string;
  priority: 'Critical' | 'High' | 'Medium' | 'Low';
  estimatedCost: number;
  justification: string;
  submittedBy: string; // employeeId
  status: 'Submitted' | 'In Review' | 'Approved for Funding' | 'Deferred';
}

export interface CapitalPlanItem {
  id: string;
  projectName: string;
  fiscalYear: number;
  projectedCost: number;
  fundingStatus: 'Funded' | 'Partial' | 'Unfunded';
  priorityScore: number;
}

export interface Invoice {
  id: string;
  vendorId: string;
  invoiceNumber: string;
  invoiceDate: string;
  dueDate: string;
  amount: number;
  status: 'Draft' | 'Submitted' | 'Approved' | 'Paid' | 'Disputed';
  purchaseOrderId?: string;
  workOrderId?: string;
  documentId: string;
}

export interface PurchaseOrder {
  id: string;
  vendorId: string;
  orderDate: string;
  totalAmount: number;
  status: 'Draft' | 'Issued' | 'Partially Received' | 'Received' | 'Closed';
  workOrderId?: string;
  projectId?: string;
  items: { description: string; quantity: number; unitPrice: number }[];
}

export interface Chargeback {
  id: string;
  fromCostCenterId: string;
  toCostCenterId: string;
  amount: number;
  date: string;
  description: string; // e.g. "Space Usage Q4", "WO-2024-891 Cost"
  type: 'Space' | 'Service';
}

// --- NEW USACE REMIS INTERFACES ---

export interface AuditEvent {
  timestamp: string;
  user: string;
  action: string;
  details?: string;
}

export interface AssetComponent {
  id: string;
  parentAssetId: string;
  parentImprovementId?: string; // Points to another AssetComponent ID if type is 'Improvement'
  name: string;
  type: 'Improvement' | 'Component' | 'Betterment';
  lifecycleState: 'Planned' | 'Active' | 'Modified' | 'Retired' | 'Archived';
  installDate: string;
  cost: number;
  appraisalValue?: number; // Only for Improvements
  description?: string;
  history?: AuditEvent[];
}

export interface RealPropertyAsset {
  id: string;
  rpuid: string; // Real Property Unique Identifier
  name: string;
  assetCategoryCode: string;
  type: 'Land' | 'Building' | 'Structure' | 'Linear Structure';
  status: 'Active' | 'Excess' | 'Disposed' | 'In Progress' | 'Archive';
  location: string; // Could be GIS data
  acquisitionDate: string;
  cost: number;
  area: number; // Acres or SqFt
  unit: 'Acres' | 'SqFt';
  program: 'Military' | 'Civil Works';
  mobilizationUse: boolean;
  cefmsSyncStatus: 'Synced' | 'Pending' | 'Error';
  components?: AssetComponent[];
  history?: AuditEvent[];
}

export interface UtilizationSummary {
    id: string;
    outGrantId: string;
    observedUse: string;
    isCompliant: boolean;
    lastUpdated: string;
    updatedBy: string;
}

export interface OutGrantInspection {
  id: string;
  outGrantId: string;
  inspectionDate: string;
  type: 'Routine' | 'Compliance' | 'Termination';
  inspector: string; // employeeId
  findings: string;
  correctiveActions?: string;
  status: 'Scheduled' | 'Completed' | 'Reviewed' | 'Closed';
  reportDocumentId?: string;
}

// Replaced UtilizationInspection with OutGrantInspection for Requirement 12 specificity
export type UtilizationInspection = OutGrantInspection;

export interface OutGrant {
  id: string;
  assetId: string;
  grantee: string;
  type: 'Lease' | 'License' | 'Easement' | 'Permit';
  authority: string; // 12.1.2
  permittedUse: string; // 12.1.2
  startDate: string;
  endDate: string;
  revenue: number; // Consideration
  lifecycleState: 'Proposed' | 'Active' | 'Amended' | 'Suspended' | 'Expired' | 'Terminated' | 'Closed' | 'Archived'; // 12.7.1
  status: string; // Mapped for backward compatibility
  utilizationSummary?: UtilizationSummary; // 12.1.3
  documentIds: string[]; // 12.1.5
  history: AuditEvent[]; // 12.8.1
}

export interface Appraisal {
  id: string;
  assetId: string;
  relatedActionId: string; // e.g., Acquisition or Disposal ID
  appraisalDate: string; // valuation date
  appraisedValue: number;
  appraiser: string;
  appraiserQualifications: string;
  type: 'Market Value' | 'In-Kind Consideration';
  purpose: 'Acquisition' | 'Disposal' | 'Outgrant';
  scope: string;
  assumptions: string;
  status: 'Initiated' | 'In Progress' | 'Under Review' | 'Approved' | 'Archived';
  documentId: string;
  history?: AuditEvent[];
}

export interface AcquisitionRecord {
  id: string;
  assetId: string;
  stage: 'Planning' | 'Site Selection' | 'NEPA Review' | 'Appraisal' | 'Negotiation' | 'Condemnation' | 'Closing' | 'Closed' | 'Terminated';
  cost: number;
  fundingSource: string;
  acquisitionMethod: 'Purchase' | 'Donation' | 'Transfer' | 'Condemnation';
  closeDate: string;
  // NEW fields for Requirement 4
  authority: string;
  purpose: string;
  statutoryBasis: string;
  interestType: 'Fee' | 'Easement' | 'Leasehold' | 'Permit';
  estateAcquired: string;
  responsibleOrg: string;
  appraisalIds: string[];
  negotiationIds: string[];
  approvalIds: string[];
  history?: AuditEvent[];
}

export interface DisposalRecord {
  id: string;
  assetId: string;
  lifecycleState: 'Initiated' | 'Excess Determined' | 'Pending Authorization' | 'Authorized' | 'Executed' | 'Closed' | 'Archived';
  stage: string; // Mapped to lifecycleState for backward compatibility

  // Creation Data
  initiatingOrg: string;
  disposalRationale: string;
  proposedMethod: 'Public Sale' | 'Transfer' | 'Donation' | 'Demolition' | 'Exchange';

  // Determination of Excess
  excessDeterminationDate?: string;
  excessDeterminationAuthority?: string;
  excessDeterminationJustification?: string;

  // Authorization
  authorizationStatus: 'Pending' | 'Approved' | 'Rejected' | 'Not Started';
  authorizationDate?: string;
  authorizingOfficial?: string;

  // Execution
  proceeds?: number;
  completionDate?: string;

  // Relationships
  appraisalIds: string[];
  environmentalSiteIds: string[];
  legalClaimIds: string[];
  documentIds: string[];

  // Audit
  history: AuditEvent[];
}

export interface RelocationBenefit {
    id: string;
    type: 'Moving Expenses' | 'Replacement Housing' | 'Business Reestablishment' | 'Advisory Services';
    amountClaimed: number;
    amountApproved: number;
    status: 'Submitted' | 'Approved' | 'Paid' | 'Rejected';
    approvalDate?: string;
    paymentReference?: string;
}

export interface RelocationCase {
    id: string;
    acquisitionId: string;
    assetId: string;
    claimantName: string; // PII Protected
    claimantType: 'Residential Owner' | 'Residential Tenant' | 'Business' | 'Farm' | 'Non-Profit';
    displacementType: 'Physical' | 'Economic';
    lifecycleState: 'Initiated' | 'Eligibility Determined' | 'Assistance Approved' | 'Assistance Provided' | 'Closed' | 'Archived';
    status: string; // Mapped to lifecycleState for list views

    // Dates
    initiationDate: string;
    eligibilityDeterminationDate?: string;
    vacationDate?: string;
    caseCloseDate?: string;

    // Financials
    totalAssistance: number; // Mapped to totalBenefitsApproved
    totalBenefitsPaid: number;

    // Benefits & Audit
    benefits: RelocationBenefit[];
    history: AuditEvent[];
    documentIds: string[];
    payments: any[]; 
}

export interface EnvironmentalSite {
  id: string;
  assetId: string;
  siteName: string;
  lifecycleState: 'Identified' | 'Assessed' | 'Under Remediation' | 'Compliant' | 'Closed' | 'Archived';
  status: string; // Mapped to lifecycleState for backward compatibility

  // Initiation
  initiatingOrg: string;
  initiationDate: string;
  authority: string;
  programApplicability: ('NEPA' | 'CERCLA' | 'RCRA' | 'Clean Water Act')[];

  // Condition Data
  contaminants: string[];
  riskClassification: 'High' | 'Medium' | 'Low';
  contaminationIndicators?: string;

  // Remediation
  remediationActions: { description: string; status: 'Planned' | 'In Progress' | 'Completed'; date: string }[];

  // Relationships
  relatedActionId?: string; // Link to Acquisition or Disposal
  documentIds: string[];

  // Audit
  history?: AuditEvent[];
}

// Updated Solicitation Interfaces
export interface BidItem {
  id: string;
  solicitationId: string;
  itemNumber: string;
  description: string;
  quantity: number;
  unit: string;
}

export interface IfbResponse {
  id: string;
  solicitationId: string;
  bidderName: string;
  submissionDate: string;
  totalBidAmount: number;
  status: 'Received' | 'Opened' | 'Evaluated' | 'Selected' | 'Rejected' | 'Archived';
  documentId?: string;
}

export interface Solicitation {
  id: string;
  assetId: string;
  title: string;
  type: 'Invitation for Bid (IFB)' | 'Request for Proposal (RFP)';
  procurementMethod: 'Sealed Bidding' | 'Negotiated' | 'Simplified';
  lifecycleState: 'Draft' | 'Issued' | 'Amended' | 'Closed' | 'Under Evaluation' | 'Awarded' | 'Cancelled' | 'Archived';
  status: string; // Mapped to lifecycleState for compatibility

  issueDate?: string;
  closeDate?: string;
  description?: string;
  pointOfContact?: string;

  // Linked data (could be separated in a real relational DB)
  bidItems?: BidItem[]; 
  responses?: IfbResponse[]; 
  documentIds: string[];
  history: AuditEvent[];

  // Legacy fields
  openDate: string;
}

export interface LegalClaim {
  id: string;
  assetId: string;

  // 9.1 Create & Claimant Info
  claimant: string; // Legacy mapping
  claimantInfo: {
    name: string;
    address?: string;
    phone?: string;
    email?: string;
  };
  claimType: 'Tort' | 'Title Dispute' | 'Contract' | 'Relocation Appeal' | 'Property Damage';

  // 9.7 Lifecycle Management
  lifecycleState: 'Received' | 'Under Investigation' | 'Adjudicated' | 'Settled' | 'Denied' | 'Paid' | 'Closed' | 'Archived';
  status: string; // Mapped to lifecycleState

  // 9.1.2 & 9.1.3 Details
  incidentDate: string;
  filedDate: string; // Date of receipt
  statutoryBasis: string; // e.g. 28 U.S.C. §§2671–2680 (FTCA)
  jurisdiction: string;
  assignedOffice: string;
  responsibleOfficial: string;
  description: string;

  // 9.3 Financials
  claimAmount: number;
  settlementAmount?: number;
  paymentDetails?: {
    amount: number;
    date: string;
    authority: string;
    transactionReference: string;
  };

  // Relationships & History
  documentIds: string[];
  history: AuditEvent[];
}

// Requirement 11: Cost-Share Program Support Interfaces
export interface CostShareContribution {
  id: string;
  type: 'Cash' | 'In-Kind' | 'LERRD' | 'Work-In-Kind';
  description: string;
  amount: number;
  valuationMethod: 'Market Value' | 'Actual Cost' | 'Negotiated Value';
  dateRecorded: string;
  status: 'Pending' | 'Verified' | 'Credited';
}

export interface CostShareAgreement {
  id: string;
  assetId: string;
  projectId: string; // e.g. "P-101"
  partner: string; // Mapped to sponsor
  sponsor: string; // Non-Federal Sponsor
  authority: string; // e.g. "WRDA 1986, Sec 103"
  statutoryBasis: string; // "33 U.S.C. §2211"

  costShareRatio: string; // "65/35" (Fed/Non-Fed)
  federalSharePercentage: number;

  totalProjectCost: number;
  partnerContribution: number; // Target

  lifecycleState: 'Initiated' | 'Agreed' | 'Active' | 'Adjusted' | 'Completed' | 'Closed' | 'Archived';
  status: string; // Mapped to lifecycle

  agreementDate: string;
  responsibleOrg: string;

  contributions: CostShareContribution[];
  documentIds: string[];
  history: AuditEvent[];
}

export interface EncroachmentCase {
  id: string;
  assetId: string;
  type: 'Structure' | 'Vegetation' | 'Use';
  dateReported: string;
  status: 'Under Investigation' | 'Notice Sent' | 'Resolution Pending' | 'Resolved';
  resolution?: string;
}

export interface MobilizationProfile {
  id: string;
  assetId: string;
  lifecycleState: 'Identified' | 'Validated' | 'Ready' | 'Activated' | 'Deactivated' | 'Archived';

  missionCriticality: 'Mission Critical' | 'Mission Essential' | 'Non-Critical';
  readinessDesignation: 'P1 - Immediate' | 'P2 - 24 Hours' | 'P3 - 72 Hours' | 'Reserve';

  facilityType: string;
  functionalCapability: string;
  condition: number;

  contingencyPlanId?: string;
  operationalRequirement?: string;

  initiatingOrg: string;
  initiationDate: string;

  lastUpdatedDate: string;
  responsibleOfficial: string;

  history: AuditEvent[];
}

export interface PermitParty {
  id: string;
  permitId: string;
  role: 'Applicant' | 'Permittee' | 'Agent';
  name: string;
  email?: string;
  phone?: string;
}

export interface PermitAddress {
  id: string;
  permitId: string;
  type: 'Mailing' | 'Site';
  addressLine1: string;
  city: string;
  state: string;
  zip: string;
}

export interface Permit {
  id: string;
  assetId: string;
