import React, { useState, FormEvent } from 'react';
import { X, Lock } from 'lucide-react';
import { AssetComponent } from '../../../types';

interface AssetStructureModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (record: Partial<AssetComponent>, reason: string) => void;
    parentAssetId: string;
    parentImprovementId?: string; // If provided, we are creating a Component (Level 3)
    existingItem?: AssetComponent;
}

export const AssetStructureModal: React.FC<AssetStructureModalProps> = ({ isOpen, onClose, onSave, parentAssetId, parentImprovementId, existingItem }) => {
    const [reason, setReason] = useState('');
    const isEditMode = !!existingItem;

    // Determine the type of item we are working with
    const defaultType = parentImprovementId ? 'Component' : 'Improvement';
    const [itemType, setItemType] = useState<AssetComponent['type']>(existingItem?.type || defaultType);

    if (!isOpen) return null;

    const handleSubmit = (e: FormEvent) => {
        e.preventDefault();
        const form = e.target as HTMLFormElement;
        const formData = new FormData(form);
        const data = Object.fromEntries(formData.entries());

        if (isEditMode && !reason) {
            alert('A "Reason for Change" is required to save modifications for audit purposes.');
            return;
        }

        const processedData = {
            ...data,
            cost: Number(data.cost),
            appraisalValue: data.appraisalValue ? Number(data.appraisalValue) : undefined,
            parentAssetId,
            parentImprovementId
        };

        onSave(processedData as any, reason);
    };

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4" onClick={onClose}>
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[90vh] flex flex-col" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center p-4 border-b">
                    <h2 className="text-lg font-bold text-slate-900">
                        {isEditMode ? `Edit ${existingItem.type}` : `Add New ${parentImprovementId ? 'Component/Betterment' : 'Improvement'}`}
                    </h2>
                    <button onClick={onClose} className="p-1 rounded-full hover:bg-slate-100"><X size={20} /></button>
                </div>
                <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-6 space-y-6">

                    {/* 15.1.1 Establishment */}
                    <div>
                        <h3 className="text-sm font-bold text-slate-900 mb-3 uppercase tracking-wider">Item Details</h3>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="md:col-span-2"><label className="text-sm font-medium">Name / Description</label><input name="name" type="text" defaultValue={existingItem?.name} className="w-full mt-1 p-2 border rounded-md" required /></div>

                            <div>
                                <label className="text-sm font-medium">Type</label>
                                <select 
                                    name="type" 
                                    value={itemType} 
                                    onChange={(e) => setItemType(e.target.value as any)} 
                                    className="w-full mt-1 p-2 border rounded-md"
                                    disabled={!!parentImprovementId && isEditMode} // Lock type if editing
                                >
                                    {!parentImprovementId && <option value="Improvement">Improvement</option>}
                                    {parentImprovementId && <option value="Component">Component</option>}
                                    {parentImprovementId && <option value="Betterment">Betterment</option>}
                                    {!parentImprovementId && !isEditMode && <option value="Betterment">Betterment (Direct)</option>}
                                </select>
                            </div>

                            <div><label className="text-sm font-medium">Lifecycle State</label><select name="lifecycleState" defaultValue={existingItem?.lifecycleState || 'Planned'} className="w-full mt-1 p-2 border rounded-md"><option>Planned</option><option>Active</option><option>Modified</option><option>Retired</option><option>Archived</option></select></div>
                            <div><label className="text-sm font-medium">Install Date</label><input name="installDate" type="date" defaultValue={existingItem?.installDate} className="w-full mt-1 p-2 border rounded-md" required /></div>
                            <div><label className="text-sm font-medium">Cost ($)</label><input name="cost" type="number" defaultValue={existingItem?.cost} className="w-full mt-1 p-2 border rounded-md" required /></div>
                        </div>
                    </div>

                    {/* 15.1.5 Valuation - Only for Improvements */}
                    {(itemType === 'Improvement' || itemType === 'Betterment') && (
                        <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-900 mb-3 uppercase tracking-wider flex items-center gap-2">Valuation <Lock size={12} className="text-slate-400"/></h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div><label className="text-sm font-medium">Appraisal Value ($)</label><input name="appraisalValue" type="number" defaultValue={existingItem?.appraisalValue} className="w-full mt-1 p-2 border rounded-md" /></div>
                                <p className="text-xs text-slate-500 md:col-span-2 mt-1">Appraisal values are recorded at the improvement level per DoDI 4165.14.</p>
                            </div>
                        </div>
                    )}

                     {isEditMode && (
                        <div className="bg-amber-50 border-l-4 border-amber-400 p-4 rounded-r-lg">
                            <label className="block text-sm font-bold text-amber-800">Reason for Change (Mandatory)</label>
                            <textarea value={reason} onChange={e => setReason(e.target.value)} placeholder="Justification for update (Req 15.3.4)..." className="mt-1 block w-full px-3 py-2 bg-white border border-slate-300 rounded-md shadow-sm" required />
                            <p className="text-xs text-amber-700 mt-1">Updates are logged in the immutable audit trail (Req 15.8.1).</p>
                        </div>
                    )}
                </form>
                <div className="p-4 bg-slate-50 border-t flex justify-end gap-2">
                    <button type="button" onClick={onClose} className="px-4 py-2 text-sm font-medium text-slate-700 bg-white border rounded-md hover:bg-slate-50">Cancel</button>
                    <button type="submit" onClick={handleSubmit} className="px-4 py-2 text-sm font-medium text-white bg-blue-600 border rounded-md hover:bg-blue-700">{isEditMode ? 'Update' : 'Add Item'}</button>
                </div>
            </div>
        </div>
    );
};

import React, { useState, FormEvent } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { USACE_ASSETS, USACE_OUTGRANTS, USACE_COMPONENTS, EMPLOYEES } from '../../services/mockData';
import { RegulatoryBadge } from '../../components/RegulatoryBadge';
import { ArrowLeft, Edit, ChevronDown, ChevronRight, Building, MapPin, Calendar, DollarSign, Square, Sigma, HardHat, FileClock, History, Plus, X, Lock, RefreshCw, Folder, FolderOpen, Layers, Archive, Trash2 } from 'lucide-react';
import { RealPropertyAsset, AuditEvent, AssetComponent } from '../../types';
import { AssetStructureModal } from './components/AssetStructureModal';

const getStatusColor = (status: string) => {
    switch(status) {
      case 'Active': return 'bg-green-100 text-green-800 border-green-200';
      case 'Excess': return 'bg-amber-100 text-amber-800 border-amber-200';
      case 'Disposed':
      case 'Archive':
         return 'bg-slate-100 text-slate-800 border-slate-200';
      default: return 'bg-blue-100 text-blue-800 border-blue-200';
    }
};

const getLifecycleColor = (state: string) => {
    switch(state) {
        case 'Active': return 'bg-green-100 text-green-800';
        case 'Planned': return 'bg-blue-100 text-blue-800';
        case 'Retired': return 'bg-red-100 text-red-800';
        case 'Archived': return 'bg-slate-200 text-slate-600';
        default: return 'bg-slate-100 text-slate-800';
    }
};

const DetailCard = ({ label, value, icon: Icon, isProtected = false }: { label: string, value: string | number | boolean, icon: any, isProtected?: boolean }) => (
    <div className="flex items-start gap-3">
        <Icon className="text-slate-400 mt-1" size={16} />
        <div>
            <div className="text-xs text-slate-500 flex items-center gap-1">{label} {isProtected && <Lock size={10} title="This field has restricted access." />}</div>
            <div className="text-sm font-medium text-slate-800">{typeof value === 'boolean' ? (value ? 'Yes' : 'No') : value}</div>
        </div>
    </div>
);

const EditAssetModal = ({ asset, isOpen, onClose, onSave }: { asset: RealPropertyAsset, isOpen: boolean, onClose: () => void, onSave: (updatedAsset: RealPropertyAsset, reason: string) => void }) => {
    if (!isOpen) return null;
    const [reason, setReason] = useState('');

    const handleSubmit = (e: FormEvent) => {
        e.preventDefault();
        if (!reason) {
            alert('A "Reason for Change" is required to save modifications.');
            return;
        }
        // In a real app, you'd gather form data here to create the updatedAsset object
        onSave(asset, reason); 
        onClose();
    }

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4" onClick={onClose}>
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[90vh] flex flex-col" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center p-4 border-b">
                    <h2 className="text-lg font-bold text-slate-900">Edit Asset Record: {asset.rpuid}</h2>
                    <button onClick={onClose} className="p-1 rounded-full hover:bg-slate-100"><X size={20} /></button>
                </div>
                <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-6 space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div><label className="block text-sm font-medium text-slate-700">Asset Name</label><input type="text" defaultValue={asset.name} className="mt-1 block w-full px-3 py-2 bg-white border border-slate-300 rounded-md shadow-sm" required /></div>
                        <div><label className="block text-sm font-medium text-slate-700">Location</label><input type="text" defaultValue={asset.location} className="mt-1 block w-full px-3 py-2 bg-white border border-slate-300 rounded-md shadow-sm" required /></div>
                    </div>
                     <div className="bg-amber-50 border-l-4 border-amber-400 p-4 rounded-r-lg">
                        <label className="block text-sm font-bold text-amber-800">Reason for Change</label>
                        <textarea value={reason} onChange={e => setReason(e.target.value)} placeholder="e.g., 'Updated location based on new survey data.'" className="mt-1 block w-full px-3 py-2 bg-white border border-slate-300 rounded-md shadow-sm" required />
                        <p className="text-xs text-amber-700 mt-1">An audit entry will be created for this update.</p>
                    </div>
                </form>
                <div className="p-4 bg-slate-50 border-t flex justify-end gap-2">
                    <button type="button" onClick={onClose} className="px-4 py-2 text-sm font-medium text-slate-700 bg-white border rounded-md hover:bg-slate-50">Cancel</button>
                    <button type="button" onClick={handleSubmit} className="px-4 py-2 text-sm font-medium text-white bg-blue-600 border rounded-md hover:bg-blue-700">Save Changes</button>
                </div>
            </div>
        </div>
    );
};


export const RemisAssetDetail: React.FC = () => {
    const { assetId } = useParams<{ assetId: string }>();
    const navigate = useNavigate();
    const [asset, setAsset] = useState<RealPropertyAsset | undefined>(USACE_ASSETS.find(a => a.id === assetId));
    const [activeTab, setActiveTab] = useState('overview');
    const [isEditModalOpen, setIsEditModalOpen] = useState(false);

    // Hierarchy Management State
    const [expandedImprovements, setExpandedImprovements] = useState<Set<string>>(new Set());
    const [isStructureModalOpen, setIsStructureModalOpen] = useState(false);
    const [structureParentId, setStructureParentId] = useState<string | undefined>(undefined);
    const [editingComponent, setEditingComponent] = useState<AssetComponent | undefined>(undefined);

    if (!asset) {
        return <div className="p-6">Asset not found. <Link to="/usace/inventory" className="text-blue-600">Return to Inventory</Link></div>;
    }

    const handleSave = (updatedAsset: RealPropertyAsset, reason: string) => {
        const newHistoryEvent: AuditEvent = {
            timestamp: new Date().toLocaleString(),
            user: 'Dr. Alistair Vance', // Simulated logged-in user
            action: 'Record Updated',
            details: reason
        };

        setAsset(prev => prev ? { ...prev, ...updatedAsset, history: [newHistoryEvent, ...prev.history!] } : undefined);
    };

    const handleStatusChange = (newStatus: RealPropertyAsset['status']) => {
        const reason = `Status changed from ${asset.status} to ${newStatus}.`;
         const newHistoryEvent: AuditEvent = {
            timestamp: new Date().toLocaleString(),
            user: 'Dr. Alistair Vance',
            action: 'Status Updated',
            details: reason,
        };
        setAsset(prev => prev ? { ...prev, status: newStatus, history: [newHistoryEvent, ...prev.history!] } : undefined);
        alert(`Asset status changed to ${newStatus}. This action has been logged.`);
    }

    // --- Hierarchy Logic ---
    const toggleImprovement = (id: string) => {
        const newSet = new Set(expandedImprovements);
        if (newSet.has(id)) newSet.delete(id);
        else newSet.add(id);
        setExpandedImprovements(newSet);
    };

    const handleAddImprovement = () => {
        setEditingComponent(undefined);
        setStructureParentId(undefined);
        setIsStructureModalOpen(true);
    };

    const handleAddComponent = (improvementId: string) => {
        // 15.1.3: Associate components with their respective parent improvements
        setEditingComponent(undefined);
        setStructureParentId(improvementId);
        setIsStructureModalOpen(true);
    };

    const handleEditStructure = (item: AssetComponent) => {
        if (item.lifecycleState === 'Retired' || item.lifecycleState === 'Archived') {
            alert('Compliance Warning (15.7.4): Retired/Archived records cannot be modified for financial reporting purposes.');
            return;
        }
        setEditingComponent(item);
        setStructureParentId(item.parentImprovementId);
        setIsStructureModalOpen(true);
    }

    const handleSaveStructure = (record: Partial<AssetComponent>, reason: string) => {
        // In a real app, this would update the state/backend
        console.log("Saving Structure:", record, reason);
        const newHistoryEvent: AuditEvent = {
            timestamp: new Date().toLocaleString(),
            user: 'Real Property Officer',
            action: editingComponent ? 'Structure Updated' : 'Structure Created',
            details: `${reason} (Item: ${record.name})`
        };

        // Simulating updating the list for demo purposes
